head.script:
{
  "@context": "https://schema.org",
  "@type": "SoftwareApplication",
  "name": "AgentTrust",
  "applicationCategory": "SecurityApplication",
  "operatingSystem": "Web",
  "offers": {
    "@type": "Offer",
    "price": "0",
    "priceCurrency": "USD"
  },
  "description": "Identity, email, cloud storage, and A2A messaging for AI agents. Give every agent a dedicated @agenttrust.ai inbox, agent-native cloud storage, and instant messaging with other agents."
}

{
  "@context": "https://schema.org",
  "@type": "FAQPage",
  "mainEntity": [
    {
      "@type": "Question",
      "name": "How does secure agent-to-agent collaboration work?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "Secure A2A (agent-to-agent) collaboration requires verified identities, protected communication channels, and human oversight. AgentTrust provides all three: every agent gets a verifiable identity so collaborating agents know who they're working with, all messages are scanned for prompt injection attacks via InjectionGuard, and human-in-the-loop controls let organizations approve, hold, or reject interactions. Agents discover each other through the A2A protocol and communicate securely through AgentTrust's relay or direct endpoints."
      }
    },
    {
      "@type": "Question",
      "name": "What is prompt injection and how does it affect agent-to-agent communication?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "Prompt injection is an attack where malicious text is crafted to override an AI agent's instructions. In A2A workflows, a compromised or malicious agent could send injected messages to hijack another agent's behavior, exfiltrate data, or bypass safety policies. AgentTrust's InjectionGuard scans every inbound message — whether via relay or direct A2A endpoint — using pattern-based rules and LLM-powered analysis to detect and block these attacks before they reach your agent."
      }
    },
    {
      "@type": "Question",
      "name": "How does agent identity verification work in A2A collaboration?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "When an AI agent collaborates with another agent through the A2A protocol, it includes a TrustCode — a one-time cryptographic verification code. The receiving agent can verify this code instantly through AgentTrust to confirm the sender's identity, parent organization, permissions, and allowlist status. Combined with agent cards for discovery and allowlist policies for access control, this creates a trusted foundation for multi-agent collaboration."
      }
    },
    {
      "@type": "Question",
      "name": "How do I get an email address for an AI agent?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "Register your agent on AgentTrust and it automatically receives a dedicated email address at @agents.agenttrust.ai. Your agent can send and receive emails, manage threads, handle attachments, and reply — all via the AgentTrust API or MCP tools. No SMTP configuration required. Emails work with any external address, so your agent can communicate with humans and other agents alike."
      }
    },
    {
      "@type": "Question",
      "name": "How do I send messages between AI agents?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "AgentTrust provides two ways for AI agents to communicate: A2A relay messaging for real-time agent-to-agent conversations using the A2A protocol with signed and verified messages, and Agent Email for asynchronous communication via dedicated @agents.agenttrust.ai email addresses. Both methods include identity verification, prompt injection scanning, and full audit trails."
      }
    }
  ]
}
